kiroAgent.trustedCommands:
$lines = [System.IO.File]::ReadAllLines("index.html")
$found = $false
for($i=0; $i -lt $lines.Length; $i++) {
  if($lines[$i] -match "localStorage") {
    Write-Host "Line $($i+1): $($lines[$i].Trim())"
    $found = $true
  }
}
if(-not $found) { Write-Host "No localStorage references remaining." }

Write-Host "=== index.html (landing) refs ==="
Select-String -Path "index.html" -Pattern "landing\.html|index\.html|app\.html" | ForEach-Object { "  Line $($_.LineNumber): $($_.Line.Trim().Substring(0,[Math]::Min(100,$_.Line.Trim().Length)))" }

Write-Host "`n=== app.html (dashboard) refs ==="
Select-String -Path "app.html" -Pattern "landing\.html|index\.html|app\.html" | ForEach-Object { "  Line $($_.LineNumber): $($_.Line.Trim().Substring(0,[Math]::Min(100,$_.Line.Trim().Length)))" }

Write-Host "`n=== supabase-client.js refs ==="
Select-String -Path "supabase-client.js" -Pattern "landing\.html|index\.html|app\.html" | ForEach-Object { "  Line $($_.LineNumber): $($_.Line.Trim().Substring(0,[Math]::Min(100,$_.Line.Trim().Length)))" }

Write-Host "=== index.html (landing page) .html refs ==="
$lines = [System.IO.File]::ReadAllLines("index.html")
for($i=0;$i -lt $lines.Length;$i++){if($lines[$i] -match "\.html"){Write-Host "  L$($i+1): $($lines[$i].Trim().Substring(0,[Math]::Min(110,$lines[$i].Trim().Length)))"}}

Write-Host "`n=== app.html (dashboard) .html refs ==="
$lines2 = [System.IO.File]::ReadAllLines("app.html")
for($i=0;$i -lt $lines2.Length;$i++){if($lines2[$i] -match "\.html"){Write-Host "  L$($i+1): $($lines2[$i].Trim().Substring(0,[Math]::Min(110,$lines2[$i].Trim().Length)))"}}

Write-Host "`n=== supabase-client.js .html refs ==="
$lines3 = [System.IO.File]::ReadAllLines("supabase-client.js")
for($i=0;$i -lt $lines3.Length;$i++){if($lines3[$i] -match "\.html"){Write-Host "  L$($i+1): $($lines3[$i].Trim().Substring(0,[Math]::Min(110,$lines3[$i].Trim().Length)))"}}
